from typing import List

def find_closest_elements(numbers: List[float]) -> Tuple[float, float]:
    if not numbers or len(numbers) == 1:
        raise ValueError("List must have more than one element")

    smallest = next(numbers)
    next_to_smallest = None

    for num in numbers:
        if num < smallest:
            next_to_smallest = smallest
            smallest = num
        elif next_to_smallest is None or abs(num - next_to_smallest) < abs(smallest - next_to_smallest):
            next_to_smallest = num

    return next_to_smallest, smallest

