def find_closest_elements(numbers):
    # First sort the list of numbers to simplify finding nearest neighbors
    sorted_numbers = sorted(numbers)

    # Check the edge cases for a single element list or empty list
    if len(sorted_numbers) <= 1:
        return sorted_numbers

    closest_pair = []
    for i in range(len(sorted_numbers) - 1):
        current_pair = [sorted_numbers[i], sorted_numbers[i + 1]]
        # Update if this pair has a closer difference than the previous one found
        if abs(current_pair[0] - current_pair[1]) < abs(closest_pair[0] - closest_pair[1]):
            closest_pair = current_pair

    return closest_pair

import numpy as np

def rescale_to_unit(numbers):
    min_val = np.min(numbers)
    max_val = np.max(numbers)
    scaled_numbers = (numbers - min_val) / (max_val - min_val) if max_val - min_val != 0 else np.array([0])
    return scaled_numbers.tolist()

